package com.infy.inventrack.catalog.service;
import com.infy.inventrack.catalog.entity.Category; import com.infy.inventrack.catalog.mapper.CatalogMapper; import com.infy.inventrack.catalog.repository.*; import com.infy.inventrack.common.constants.InfyInvenTrackConstants; import com.infy.inventrack.common.dto.*; import com.infy.inventrack.common.exception.*; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service public class CategoryService { private final CategoryRepository categories; private final ProductRepository products; public CategoryService(CategoryRepository c, ProductRepository p){categories=c;products=p;} @Transactional @PreAuthorize("hasRole('ADMIN')") public String createCategory(CategoryRequest r){ if(categories.existsByNameIgnoreCase(r.getName().trim())) throw new DuplicateResourceException(InfyInvenTrackConstants.DUPLICATE_CATEGORY.value()); Category c=new Category(); c.setName(r.getName().trim()); categories.save(c); return InfyInvenTrackConstants.CATEGORY_CREATED.value(); } @Transactional @PreAuthorize("hasRole('ADMIN')") public CategoryResponse updateCategory(Integer id, CategoryRequest r){ Category c=categories.findById(id).orElseThrow(()->new ResourceNotFoundException(InfyInvenTrackConstants.CATEGORY_NOT_FOUND.value())); categories.findByNameIgnoreCase(r.getName().trim()).filter(e->!e.getId().equals(id)).ifPresent(e->{throw new DuplicateResourceException(InfyInvenTrackConstants.DUPLICATE_CATEGORY.value());}); c.setName(r.getName().trim()); return CatalogMapper.toCategoryResponse(categories.save(c)); } @Transactional @PreAuthorize("hasRole('ADMIN')") public String deleteCategory(Integer id){ Category c=categories.findById(id).orElseThrow(()->new ResourceNotFoundException(InfyInvenTrackConstants.CATEGORY_NOT_FOUND.value())); if(products.existsByCategoryId(id)) throw new BusinessValidationException("Category is in use and cannot be deleted"); categories.delete(c); return InfyInvenTrackConstants.CATEGORY_DELETED.value(); } }
